思路：模拟
+
自定义排序
对输入字符串按空格分割，得到每组分辨率规格。
对每组分辨率计算对应清晰度等级、面积。
按规则排序：
先按清晰度降序
清晰度相同按面积降序
面积相同按宽降序
输出排序后的结果。
C++
#include<iostream>
#include<vector>
#include<string>
#include <utility>
#include <sstream>
#include<algorithm>
#include<cmath>
#include<map>
using namespace std;
struct node{
int height;
int width;
int level;
int area;
node(int width, int
height, int level, int
area):width(width),height(height),level(level),area(area) {}
};
//
通用 切割函数 函数 将字符串
str
根据
delimiter
进行切割
vector<string> split(const
string& str, const string& delimiter) {
vector<string>
result;
size_t start = 0;
size_t end =
str.find(delimiter);
while (end !=
string::npos) {
result.push_back(str.substr(start, end - start));
start = end + delimiter.length();
end = str.find(delimiter, start);
}
//
添加最后一个部分
result.push_back(str.substr(start));
return result;
}
//
获取对应分辨率
int getLevel(int width, int height) {
if (width >= 3840
&& height >= 2160) return 4;
if (width >= 2560
&& height >= 1440) return 3;
if (width >= 1920
&& height >= 1080) return 2;
return 1;
}
string resolutionSort(string& input) {
vector<string>
items= split(input, " ");
int n = items.size();
vector<node>
nodes;
for (int i = 0; i <
n; i++) {
string item = items[i];
vector<string> tmp = split(item, "x");
int width = stoi(tmp[0]);
int height = stoi(tmp[1]);
int level = getLevel(width, height);
int area = width * height;
nodes.push_back({width, height, level, area});
}
//
自定义排序
sort(nodes.begin(),
nodes.end(), [](node& a, node& b) {
if (a.level != b.level) {
return a.level > b.level;
}
if (a.area != b.area) {
return a.area > b.area;
}
return a.width > b.width;
});
//
构建结果字符串
string res;
for (int i = 0; i <
nodes.size(); i++) {
node a = nodes[i];
int width = a.width;
int height = a.height;
res += (to_string(width) + "x" + to_string(height));
if (i != nodes.size() -1) {
res += " ";
}
}
return res;
}
int main() {
string input;
getline(cin, input);
string res =
resolutionSort(input);
cout << res;
return 0;
}
